import xml.etree.ElementTree as ET
from xml.dom import minidom
import os
from typing import Optional, Dict, Any, List


def validate_xml_file(
    file_path: str,
    max_size_mb: float = 10,
    allowed_root_tags: Optional[List[str]] = None,
    required_elements: Optional[List[str]] = None,
    xsd_path: Optional[str] = None
) -> Dict[str, Any]:
    """
    Reads and validates an XML document uploaded by a user.
    
    Args:
        file_path: Path to the XML file
        max_size_mb: Maximum allowed file size in MB
        allowed_root_tags: List of allowed root tag names (None = any)
        required_elements: List of required element tag names
        xsd_path: Path to XSD schema file for validation (optional)
    
    Returns:
        Dictionary with validation results containing:
        - valid: Boolean indicating if XML is valid
        - errors: List of error messages
        - warnings: List of warning messages
        - root_tag: Root element tag name
        - element_count: Total number of elements
        - tree: Parsed ElementTree object (if valid)
    """
    result = {
        'valid': False,
        'errors': [],
        'warnings': [],
        'root_tag': None,
        'element_count': 0,
        'tree': None
    }
    
    if not os.path.exists(file_path):
        result['errors'].append(f"File not found: {file_path}")
        return result
    
    file_size_mb = os.path.getsize(file_path) / (1024 * 1024)
    if file_size_mb > max_size_mb:
        result['errors'].append(f"File size ({file_size_mb:.2f} MB) exceeds maximum allowed size ({max_size_mb} MB)")
        return result
    
    try:
        tree = ET.parse(file_path)
        root = tree.getroot()
        result['root_tag'] = root.tag
        result['tree'] = tree
        
        all_elements = list(root.iter())
        result['element_count'] = len(all_elements)
        
        if allowed_root_tags and root.tag not in allowed_root_tags:
            result['errors'].append(f"Root tag '{root.tag}' is not in allowed list: {allowed_root_tags}")
            return result
        
        if required_elements:
            found_tags = {elem.tag for elem in all_elements}
            missing_elements = set(required_elements) - found_tags
            if missing_elements:
                result['errors'].append(f"Missing required elements: {', '.join(missing_elements)}")
                return result
        
        if xsd_path:
            try:
                from lxml import etree
                with open(xsd_path, 'rb') as xsd_file:
                    schema_root = etree.XML(xsd_file.read())
                    schema = etree.XMLSchema(schema_root)
                
                with open(file_path, 'rb') as xml_file:
                    xml_doc = etree.parse(xml_file)
                
                if not schema.validate(xml_doc):
                    for error in schema.error_log:
                        result['errors'].append(f"XSD validation error: {error.message}")
                    return result
            except ImportError:
                result['warnings'].append("lxml not installed, XSD validation skipped")
            except Exception as e:
                result['errors'].append(f"XSD validation error: {str(e)}")
                return result
        
        result['valid'] = True
        
    except ET.ParseError as e:
        result['errors'].append(f"XML parsing error: {str(e)}")
    except Exception as e:
        result['errors'].append(f"Unexpected error: {str(e)}")
    
    return result


def read_xml_file(file_path: str) -> Optional[ET.ElementTree]:
    """
    Simple function to read and parse an XML file.
    
    Args:
        file_path: Path to the XML file
    
    Returns:
        ElementTree object or None if parsing fails
    """
    try:
        tree = ET.parse(file_path)
        return tree
    except Exception as e:
        print(f"Error reading XML file: {str(e)}")
        return None


def pretty_print_xml(tree: ET.ElementTree) -> str:
    """
    Convert ElementTree to pretty-printed XML string.
    
    Args:
        tree: ElementTree object
    
    Returns:
        Pretty-printed XML string
    """
    xml_str = ET.tostring(tree.getroot(), encoding='unicode')
    dom = minidom.parseString(xml_str)
    return dom.toprettyxml(indent="  ")


def validate_xml_string(xml_string: str) -> Dict[str, Any]:
    """
    Validates an XML string.
    
    Args:
        xml_string: XML content as string
    
    Returns:
        Dictionary with validation results
    """
    result = {
        'valid': False,
        'errors': [],
        'warnings': [],
        'root_tag': None,
        'element_count': 0,
        'tree': None
    }
    
    try:
        root = ET.fromstring(xml_string)
        tree = ET.ElementTree(root)
        result['root_tag'] = root.tag
        result['tree'] = tree
        result['element_count'] = len(list(root.iter()))
        result['valid'] = True
    except ET.ParseError as e:
        result['errors'].append(f"XML parsing error: {str(e)}")
    except Exception as e:
        result['errors'].append(f"Unexpected error: {str(e)}")
    
    return result